// Replays flutter/test/goldens/commitmentload_goldens.json, generated by
// executing the REAL RN analytics.js monthlySeries inside the reference
// reconciliation. The spoken-for share and every peso must match the live
// engine. See scratchpad/gen-commitmentload-goldens.js.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/commitmentload.dart';

dynamic normalize(dynamic v) {
  if (v is num) return v.toDouble();
  if (v is Map) return v.map((k, x) => MapEntry(k.toString(), normalize(x)));
  if (v is List) return v.map(normalize).toList();
  return v;
}

void main() {
  final raw = jsonDecode(
          File('test/goldens/commitmentload_goldens.json').readAsStringSync())
      as Map<String, dynamic>;
  final ref = DateTime(2026, 7, 16, 12);
  final fixtures = raw['fixtures'] as Map<String, dynamic>;
  final cases = raw['cases'] as Map<String, dynamic>;

  for (final name in cases.keys) {
    test('commitmentLoad matches the RN engine: $name', () {
      final data = (fixtures[name] as Map).cast<String, dynamic>();
      expect(normalize(commitmentLoad(data, ref)), normalize(cases[name]),
          reason: name);
    });
  }
}
